/// Check if there's a dominating condition that V1 != V2, which implies
/// V1 | V2 != 0 (since if V1 | V2 == 0, then V1 == 0 and V2 == 0, so V1 == V2).
static bool isKnownNonEqualFromDominatingCondition(const Value *V1,
                                                    const Value *V2,
                                                    const Instruction *CtxI,
                                                    const DominatorTree *DT) {
  assert(!isa<Constant>(V1) && !isa<Constant>(V2) && "Called for constant?");

  if (!CtxI || !DT || V1->getType() != V2->getType())
    return false;

  unsigned NumUsesExplored = 0;
  for (auto &U : V1->uses()) {
    // Avoid massive lists
    if (NumUsesExplored >= DomConditionsMaxUses)
      break;
    NumUsesExplored++;

    const Instruction *UI = cast<Instruction>(U.getUser());

    // Look for icmp ne V1, V2 or icmp ne V2, V1
    CmpPredicate Pred;
    Value *LHS, *RHS;
    if (!match(UI, m_c_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
      continue;

    // Check if this is a "not equal" comparison between V1 and V2
    if (Pred != CmpInst::ICMP_NE)
      continue;
    if (!((LHS == V1 && RHS == V2) || (LHS == V2 && RHS == V1)))
      continue;

    // Now check if this comparison dominates CtxI through a branch
    SmallVector<const User *, 4> WorkList;
    SmallPtrSet<const User *, 4> Visited;
    for (const auto *CmpU : UI->users()) {
      if (Visited.insert(CmpU).second)
        WorkList.push_back(CmpU);

      while (!WorkList.empty()) {
        auto *Curr = WorkList.pop_back_val();

        // Propagate through AND (only true branch matters for NE condition)
        if (match(Curr, m_LogicalAnd(m_Value(), m_Value()))) {
          for (const auto *CurrU : Curr->users())
            if (Visited.insert(CurrU).second)
              WorkList.push_back(CurrU);
          continue;
        }

        if (const BranchInst *BI = dyn_cast<BranchInst>(Curr)) {
          assert(BI->isConditional() && "uses a comparison!");
          // For NE, we want the true successor (when V1 != V2)
          BasicBlock *NonEqualSuccessor = BI->getSuccessor(0);
          BasicBlockEdge Edge(BI->getParent(), NonEqualSuccessor);
          if (Edge.isSingleEdge() && DT->dominates(Edge, CtxI->getParent()))
            return true;
        } else if (isGuard(Curr) && DT->dominates(cast<Instruction>(Curr), CtxI)) {
          return true;
        }
      }
    }
  }

  return false;
}

